UPDATE TBL_SO_P
SET SCAN_QTY = ISNULL(SCAN_QTY, 0) + 1
WHERE TBL_SO_P_ID = #{tblSoPId}

UPDATE TBL_STOCK
SET STOCK_QTY = STOCK_QTY - 1,
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{userId}
WHERE STOCK_ID = #{stockId}
  AND STOCK_QTY > 0

mapper.select:
SELECT ISNULL(STOCK_QTY, 0)
FROM TBL_STOCK
WHERE STOCK_ID = #{stockId}

mapper.update:
UPDATE TBL_STOCK
SET STOCK_QTY = STOCK_QTY - #{moveQty},
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{userId}
WHERE STOCK_ID = #{stockId}

UPDATE TBL_NOTICE
SET CONFIRM_YN = 'Y', CONFIRM_TIME = GETDATE()
WHERE NOTICE_ID = #{noticeId}
